import './App.css';
import { useState, useEffect } from "react";
import { Routes, Route } from "react-router-dom";
import userService from "./utils/userService";
import Login from './pages/Login/Login';
import Signup from './pages/Signup/Signup';
import Layout from "./components/Layout/Layout";
import Homepage from './pages/Homepage/Homepage.jsx';
import Profile from './pages/Profile/Profile.jsx'
import NewPost from './pages/Create/NewPost';
import EditPost from './pages/Update/EditPost';
import DeletePost from './pages/Delete/DeletePost';
import Comments from './components/Comments/Comments';
// import NewComment from './pages/Create/NewComment.jsx'

function App() {
  // const [state, setState] = useState({})
  const [user, setUser] = useState({});
  const [posts, setPosts]= useState({})
  // const [comments, setComments]= useState({})

  useEffect(() => {
    console.log('useEffect Ran!')
    fetch('http://localhost:8000/bunnybook/posts/')
    .then(res => res.json())
    .then(res => {
      // setState(res)
      return res
    }).then(res => console.log(res))
  }, []) 



const handleSignupOrLogin = () => {
  setUser(userService.getUser())
}


const handleLogout = () => {
    userService.logout();
    setUser(null)
}

const addPost = (post) => {
  setPosts([...posts, post]);
};

// const addComment = (comment) => {
//   setComments([...comments, comment]);
// };

const updatePost = (id) => {
  setPosts(posts.filter((post) => post._id !== id));
};



  return (
    <Layout user={user} setUser={setUser} handleLogout={handleLogout} >

      <Routes>
      <Route path="/register" element={<Signup />}/>
      <Route path="/login" element={<Login handleSignupOrLogin={handleSignupOrLogin} setUser={setUser} />} />
      <Route path="/new-post" element={<NewPost addItem={addPost} />} />
      {/* <Route path="/new-comment" element={<NewComment addItem={addComment} />} /> */}
      <Route
          path="/posts/edit/:id"
          element={<EditPost setPosts={setPosts} />}
        />
         <Route path="/posts/:id" element={<DeletePost updatePost={updatePost} posts={posts} />} />
         {/* <Route path="/comments/:id" element={<Comments comments={comments} updateComment={updateComment} user={user} />} /> */}
        <Route path='/posts' element={<Homepage />} />
        <Route path='/profile' element={<Profile />} />

      </Routes>
    </Layout>
  );
}

export default App;
